v.cell_size = 140; v.warp_freq = 0.01;     v.warp_strength = 300;   v.seed = 1000;
v.wx = v.originx + q.noise((v.originx + v.seed) * v.warp_freq, v.originz * v.warp_freq) * v.warp_strength; v.wz = v.originz + q.noise((v.originx + 1000 + v.seed) * v.warp_freq, (v.originz + 1000) * v.warp_freq) * v.warp_strength;
v.sx = math.floor(v.wx / v.cell_size); v.sz = math.floor(v.wz / v.cell_size);
v.cx = v.sx * v.cell_size + v.cell_size * 0.5; v.cz = v.sz * v.cell_size + v.cell_size * 0.5;
v.dx = math.abs(v.wx - v.cx); v.dz = math.abs(v.wz - v.cz);
v.norm = math.max(v.dx, v.dz) / (v.cell_size * 0.5);
return v.norm > 0.9 ;
